   640|  const rowByName = new Map(rows.map((row) => [row.name, row]));
   641|  const providers = Array.from(new Set(OWNER_VARIABLES.map((item) => item.provider))) as OwnerVariableProvider[];
   642|  return Object.fromEntries(providers.map((provider) => {
   643|    const required = OWNER_VARIABLES.filter((item) => item.provider === provider && item.required).map((item) => item.name);
   644|    const saved = required.filter((name) => rowByName.has(name));
   645|    const missing = required.filter((name) => !rowByName.has(name));
   646|    const providerRows = OWNER_VARIABLES.filter((item) => item.provider === provider).map((item) => rowByName.get(item.name)).filter((row): row is OwnerVariableRow => Boolean(row));
   647|    const hasInvalid = providerRows.some((row) => row.status === 'invalid');
   648|    const hasTested = required.length > 0 && required.every((name) => rowByName.get(name)?.status === 'tested');
   649|    const lastTestedAt = providerRows
   650|      .map((row) => row.last_tested_at)
   651|      .filter((value): value is string => Boolean(value))
   652|      .sort()
   653|      .at(-1) ?? null;
   654|    const status: ProviderReadiness['status'] = missing.length > 0 ? 'missing' : hasInvalid ? 'invalid' : hasTested ? 'tested' : 'saved';
   655|    return [provider, {
   656|      provider,
   657|      status,
   658|      requiredVariableNames: required,
   659|      savedVariableNames: saved,
   660|      missingVariableNames: missing,
   661|      lastTestedAt,
   662|      secretValuesReturned: false,
   663|    }];
   664|  })) as Record<OwnerVariableProvider, ProviderReadiness>;
