                .padding(20)
            }
            .background(Color.ivxBackground)
            .navigationTitle("Edit Credential")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .topBarLeading) {
                    Button("Cancel") { dismiss() }
                        .foregroundStyle(Color.ivxGold)
                }
