                        .font(.caption2)
                        .foregroundStyle(Color.ivxTextTertiary)
                    Button {
                        onSave(SaveDraft(name: name, value: value))
                        dismiss()
                    } label: {
                        Text("Save securely")
                            .font(.subheadline)
                            .fontWeight(.bold)
                            .foregroundStyle(Color.ivxBackground)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 14)
